var allRows = [];
function platformClass(p) {
  if (!p) return 'platform-default';
  p = p.toLowerCase();
  if (p === 'amazon') return 'platform-amazon';
  if (p === 'ebay') return 'platform-ebay';
  if (p === 'backmarket') return 'platform-backmarket';
  return 'platform-default';
}
function formatDate(str) {
  if (!str) return '—';
  return new Date(str).toLocaleDateString('en-GB', {
    day: '2-digit',
    month: '2-digit',
    year: '2-digit'
  });
}
function formatTotal(val) {
  if (val === null || val === undefined || val === '') return '—';
  return '£' + Number(val).toFixed(2);
}
function populatePlatforms(rows) {
  var seen = {};
  var sel = document.getElementById('filter_platform');
  var current = sel.value;
  while (sel.options.length > 1) sel.remove(1);
  rows.forEach(function (r) {
    var p = (r.platform || '').toLowerCase();
    if (p && p !== 'unknown' && !seen[p]) {
      seen[p] = true;
      var opt = document.createElement('option');
      opt.value = p;
      opt.textContent = p.charAt(0).toUpperCase() + p.slice(1);
      sel.appendChild(opt);
    }
  });
  if (current) sel.value = current;
}
function renderTable(rows) {
  var tbody = document.getElementById('table_body');
  document.getElementById('record_count').textContent = rows.length + ' record' + (rows.length !== 1 ? 's' : '');
  if (!rows.length) {
    tbody.innerHTML = '<tr><td colspan="7" class="empty">No sales records found</td></tr>';
    return;
  }
  tbody.innerHTML = rows.map(function (r) {
    return '<tr>' + '<td><span class="sale-ref">' + (r.sale_ref || '—') + '</span></td>' + '<td><span class="platform-badge ' + platformClass(r.platform) + '">' + (r.platform || 'Unknown') + '</span></td>' + '<td>' + formatDate(r.sale_date) + '</td>' + '<td><span class="asset-refs">' + (r.asset_refs || '—') + '</span></td>' + '<td><span class="models">' + (r.models || '—') + '</span></td>' + '<td><span class="total">' + formatTotal(r.total_price) + '</span></td>' + '<td><button class="btn-view" onclick="window.viewSale(' + r.sale_id + ')">View</button></td>' + '</tr>';
  }).join('');
}
window.applyFilters = function () {
  var platform = document.getElementById('filter_platform').value.toLowerCase();
  var ref = document.getElementById('filter_ref').value.toLowerCase();
  var from = document.getElementById('filter_from').value;
  var to = document.getElementById('filter_to').value;
  var filtered = allRows.filter(function (r) {
    if (platform && (r.platform || '').toLowerCase() !== platform) return false;
    if (ref && !(r.sale_ref || '').toLowerCase().includes(ref)) return false;
    if (from && new Date(r.sale_date) < new Date(from)) return false;
    if (to && new Date(r.sale_date) > new Date(to + 'T23:59:59')) return false;
    return true;
  });
  renderTable(filtered);
};
window.clearFilters = function () {
  document.getElementById('filter_platform').value = '';
  document.getElementById('filter_ref').value = '';
  document.getElementById('filter_from').value = '';
  document.getElementById('filter_to').value = '';
  renderTable(allRows);
};
window.viewSale = function (sale_id) {
  appsmith.updateModel({
    selectedSaleId: sale_id
  });
  appsmith.triggerEvent('onViewSale');
};
function render(model) {
  allRows = model && model.sales ? model.sales : [];
  populatePlatforms(allRows);
  window.applyFilters();
}
appsmith.onReady(function () {
  render(appsmith.model);
});
appsmith.onModelChange(function () {
  render(appsmith.model);
});

